INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$83df2e22-9c2d-49e6-b49a-144860159b63$$, $$Grove Ridge$$, $$grove-ridge-bayut-3352$$, $$9b4df28f-d810-429d-b1f0-c09d4e9093bf$$, $$Emaar South, Dubai South, Dubai$$, $$Dubai South$$, $$Emaar South$$, 1270000, NULL, ARRAY[1,2,3], $$2029-09-29$$, $$10/70/20$$, 6.5, FALSE, $$selling$$, $$Grove Ridge will be a residential development in Dubai South, set within a growing district defined by open landscapes and well-structured neighbourhoods. The off-plan project by Emaar Properties will offer a collection of residential units designed to support practical living. The development will focus on ease and functionality, combining open interiors with green surroundings to create a calm setting. Residents will have access to a wide array of amenities, including a swimming pool, a kids’ play area, a garden and a gym, supporting leisure and wellness needs. The project will connect via Dubai–Al Ain Road (E66) and Sheikh Mohammed Bin Zayed Road (E311), providing convenient access across Dubai.$$, '{}', $$apartment$$, $$Invest in Dubai South$$, NULL, 788, NULL, $$published$$, $$under-construction$$, 30, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{}', NULL, '{}', NULL, NULL, NULL);
INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$e4fc5e0b-b29b-48d8-b1a9-f28fe3bfef98$$, $$The Bristol Emaar Beachfront$$, $$the-bristol-emaar-beachfront-bayut-2368$$, $$9b4df28f-d810-429d-b1f0-c09d4e9093bf$$, $$Emaar Beachfront, Dubai Harbour, Dubai$$, $$Dubai Harbour$$, $$Emaar Beachfront$$, 3400000, NULL, ARRAY[1,2,3,4,5], $$2029-09-29$$, $$10/70/20$$, 7.0, TRUE, $$selling$$, $$The Bristol Emaar Beachfront will offer an exceptional waterfront living experience in one of Dubai’s most prestigious locations. It will provide breathtaking views of the Arabian Gulf, Palm Jumeirah and Dubai Marina. The project by Emaar Properties will feature an exclusive selection of 1 to 4-bedroom apartments, all designed with modern interiors and high-quality finishes. 
INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$f97c90f5-05fe-496f-86fb-79f2c4e0ed6f$$, $$Greencrest$$, $$greencrest-bayut-3431$$, $$9b4df28f-d810-429d-b1f0-c09d4e9093bf$$, $$Greencrest, Dubai Hills Estate, Dubai$$, $$Dubai Hills Estate$$, $$Greencrest$$, 1570000, NULL, ARRAY[1,2,3], $$2029-06-29$$, $$10/70/20$$, 6.5, FALSE, $$selling$$, $$Greencrest at Dubai Hills Estate is a refined residential address where contemporary design meets nature-led living. Overlooking the lush fairways of Dubai Hills Golf Course, this tranquil community offers a balanced lifestyle shaped by greenery, light and open spaces. 
INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$b1aa5b5c-b2e6-49c6-b95f-048483c08e2d$$, $$Seychelles 2$$, $$seychelles-2-bayut-2914$$, $$1c6eb5a3-55f5-4bf8-ac37-0e96b15fe0be$$, $$Seychelles 2, DAMAC Islands, Dubai$$, $$DAMAC Islands$$, $$Seychelles 2$$, 2750000, NULL, ARRAY[4,5,6], $$2029-06-29$$, $$20/55/25$$, 7.0, TRUE, $$selling$$, $$Seychelles 2 at DAMAC Islands is a luxurious off-plan residential enclave by DAMAC Properties, nestled in the heart of Dubailand. Offering spacious 4 and 5-bedroom residences, the upcoming project will blend tropical tranquillity with modern elegance. Each home will feature high-end finishes including marble countertops, porcelain flooring and walnut wood accents. 
INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$f3f9d1c5-7c05-4ddf-9935-1de4028e2496$$, $$Selvara 4$$, $$selvara-4-bayut-2985$$, $$9b4df28f-d810-429d-b1f0-c09d4e9093bf$$, $$Grand Polo Club & Resort, Dubai Investment Park (DIP), Dubai$$, $$Dubai Investment Park (DIP)$$, $$Grand Polo Club & Resort$$, 6430000, NULL, ARRAY[4], $$2029-05-30$$, $$10/70/20$$, 7.0, TRUE, $$selling$$, $$Selvara 4 at Grand Polo Club & Resort is an exclusive off-plan community by Emaar Properties, set to bring a new standard of sophisticated living. The project will present a limited collection of 4-bedroom luxury villas. Showcasing contemporary architecture with natural clay, stone and soft neutral facades, each residence will feature open interiors, travertine floors, bespoke wood detailing and spacious courtyards. 
INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$122669b2-bbc0-4a64-a8c5-930325abcf79$$, $$Selvara 3$$, $$selvara-3-bayut-2988$$, $$9b4df28f-d810-429d-b1f0-c09d4e9093bf$$, $$Grand Polo Club & Resort, Dubai Investment Park (DIP), Dubai$$, $$Dubai Investment Park (DIP)$$, $$Grand Polo Club & Resort$$, 6493888, NULL, ARRAY[4], $$2029-05-30$$, $$10/70/20$$, 7.0, TRUE, $$selling$$, $$Selvara 3 at Grand Polo Club & Resort is a distinguished off-plan residential enclave that will redefine modern living with elegance and refinement. Offering a curated collection of 4-bedroom luxury villas, the development by Emaar Properties will be designed for those who value timeless design and elegance. Each villa will feature contemporary architecture with clay, stone and neutral-toned facades, complemented by airy interiors, travertine flooring, hand-finished woodwork and expansive courtyards. 
INSERT INTO public.properties (id, name, slug, developer_id, location, area, community, price_from, price_to, bedrooms, completion_date, payment_plan, roi_estimate, golden_visa_eligible, status, description, features, property_type, tagline, total_units, size_sqft_from, size_sqft_to, listing_status, construction_stage, construction_percent, latitude, longitude, view_type, furnishing_status, parking_included, service_charge_sqft, rera_permit_number, dld_registration_number, virtual_tour_url, brochure_url, lifestyle_tags, lifestyle_description, exclusive_amenities, post_handover_percent, post_handover_years, architect) VALUES ($$c76ff63b-446e-4537-9c6f-214c8ea4acb4$$, $$Breez by Danube$$, $$breez-by-danube-bayut-3099$$, $$08b6a73c-da6c-47ae-8e78-ab82a84fcdb3$$, $$Breez by Danube, Dubai Maritime City, Dubai$$, $$Dubai Maritime City$$, $$Breez by Danube$$, 1400000, NULL, ARRAY[0,1,2,3], $$2029-03-30$$, $$10/60/20$$, 6.5, FALSE, $$selling$$, $$Breeze by Danube will bring a refreshing take on waterfront living to Dubai Maritime City. The 60-storey development will offer studios, 1 to 4-bedroom apartments and sky villas, each planned to capture views of the Arabian Gulf and city skyline. Everyday life will be enhanced with over 40 amenities, including infinity pools, lagoon decks, and landscaped gardens, as well as indoor and outdoor gyms, wellness spaces and yoga zones. 
